<template><div class="grid"><img v-for="(img,i) in images" :src="img" class="thumb reveal" :style="{transitionDelay:(i*120)+'ms'}" @click="open(i)"/></div><div v-if="show" class="full" @click="close"><button class="nav left" @click.stop="prev">⟨</button><img :src="current" class="img-full"/><button class="nav right" @click.stop="next">⟩</button></div></template><script setup>import{ref,computed}from "vue";const props=defineProps({images:Array});const i=ref(0),show=ref(false);const current=computed(()=>props.images[i.value]);const open=j=>{i.value=j;show.value=true;document.body.style.overflow="hidden"};const close=()=>{show.value=false;document.body.style.overflow="auto"};const next=()=>i.value=(i.value+1)%props.images.length;const prev=()=>i.value=(i.value-1+props.images.length)%props.images.length;</script><style scoped>.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px}.thumb{width:100%;border-radius:12px;cursor:pointer;transition:.3s;transform:perspective(600px) rotateY(0) rotateX(0)}.thumb:hover{transform:perspective(600px) rotateY(6deg) rotateX(3deg) scale(1.04);box-shadow:0 20px 35px #0005}.full{position:fixed;inset:0;background:#090911dd;display:flex;justify-content:center;align-items:center;z-index:9999}.img-full{max-width:90vw;max-height:80vh;border-radius:10px;box-shadow:0 0 30px #000;animation:fadeZoom .6s ease}@keyframes fadeZoom{0%{opacity:0;transform:scale(.97)}100%{opacity:1;transform:scale(1)}}.nav{position:absolute;top:50%;transform:translateY(-50%);background:none;border:none;color:white;font-size:48px;cursor:pointer}.left{left:40px}.right{right:40px}</style>